diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..e7b346b38 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1927,7 +1927,7 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 	fz_irect bbox;
 	fz_pixmap *scaled = NULL;
 	fz_pixmap *pixmap = NULL;
-	int dx, dy;
+	int dx = 1, dy = 1;
 	fz_draw_state *state = push_stack(ctx, dev, "clip image mask");
 	fz_colorspace *model = state->dest->colorspace;
 	fz_irect clip;

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..c6e3dc406 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2001,7 +2001,7 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 		state[1].blendmode |= FZ_BLEND_ISOLATED;
 		state[1].scissor = bbox;

-		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
+		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && pixmap && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
 		{
 			int gridfit = !(dev->flags & FZ_DRAWDEV_FLAGS_TYPE3);
 			scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);
@@ -3232,4 +3232,4 @@ fz_new_draw_device_with_options(fz_context *ctx, const fz_draw_options *opts, fz
 		fz_rethrow(ctx);
 	}
 	return dev;
-}
+}
\ No newline at end of file

